/**
 * @file components/tracks/TrackMaps.tsx
 * @description Accurate F1 circuit SVG components generated from FastF1
 * telemetry position data (X/Y GPS-fused coordinates recorded at 10Hz).
 *
 * Each circuit path comes from the fastest lap of the corresponding 2024
 * Race session, extracted via FastF1 `get_pos_data()`, downsampled to
 * ~200 points, and normalised to a 300x200 SVG viewBox.
 *
 * Generated: 2026-03-24 23:15 UTC
 *
 * @warning Do NOT hand-edit SVG paths — regenerate with extract_f1_tracks.py
 */

import React from 'react';
import { motion } from 'framer-motion';

// ─── Shared types ─────────────────────────────────────────────────────────────

interface TrackProps {
  width?: number;
  height?: number;
  strokeColor?: string;
  strokeWidth?: number;
  fillColor?: string;
  showSectors?: boolean;
  sectorColors?: [string, string, string];
  showStartFinish?: boolean;
  showDRS?: boolean;
  className?: string;
  animated?: boolean;
}

const defaultProps: TrackProps = {
  width: 300,
  height: 200,
  strokeColor: '#FFFFFF',
  strokeWidth: 3,
  fillColor: 'none',
  showSectors: false,
  sectorColors: ['#E10600', '#FFF200', '#00D2BE'],
  showStartFinish: true,
  showDRS: false,
  className: '',
  animated: false,
};

// ─── Animated path + F1 car marker ───────────────────────────────────────────

/**
 * Renders the circuit stroke and, when animated=true, adds a red glow sweep
 * and an F1 car icon travelling along the path using CSS offset-path.
 */
const AnimatedPath: React.FC<{
  d: string;
  strokeColor?: string;
  strokeWidth?: number;
  fillColor?: string;
  animated?: boolean;
}> = ({ d, strokeColor, strokeWidth, fillColor, animated }) => (
  <>
    <path
      d={d}
      stroke={strokeColor}
      strokeWidth={strokeWidth}
      fill={fillColor}
      strokeLinecap="round"
      strokeLinejoin="round"
      className="transition-colors duration-500"
    />
    {animated && (
      <>
        <motion.path
          d={d}
          stroke="#E10600"
          strokeWidth={(strokeWidth || 3) + 2}
          fill="none"
          strokeLinecap="round"
          strokeLinejoin="round"
          initial={{ pathLength: 0, pathOffset: 0 }}
          animate={{ pathOffset: 1 }}
          transition={{ duration: 10, ease: 'linear', repeat: Infinity }}
          style={{ pathLength: 0.06, filter: 'drop-shadow(0 0 6px #E10600)' }}
        />
        <motion.g
          initial={{ offsetDistance: '0%' }}
          animate={{ offsetDistance: '100%' }}
          transition={{ duration: 10, ease: 'linear', repeat: Infinity }}
          style={{ offsetPath: `path('${d}')`, offsetRotate: 'auto' } as any}
        >
          <g transform="scale(0.7) translate(-13,-10)">
            <rect x="0"  y="6"  width="3"  height="8"  fill="#111" rx="1" />
            <rect x="3"  y="2"  width="6"  height="5"  fill="#222" rx="1" />
            <rect x="3"  y="13" width="6"  height="5"  fill="#222" rx="1" />
            <path d="M4,7 L19,8 L19,12 L4,13 Z" fill="#E10600" />
            <circle cx="12" cy="10" r="2.5" fill="#FFE500" />
            <rect x="16" y="2"  width="6"  height="5"  fill="#222" rx="1" />
            <rect x="16" y="13" width="6"  height="5"  fill="#222" rx="1" />
            <path d="M19,9 L24,9.5 L24,10.5 L19,11 Z" fill="#E10600" />
            <rect x="23" y="5"  width="2"  height="10" fill="#111" rx="0.5" />
          </g>
        </motion.g>
      </>
    )}
  </>
);

