// ─── Helpers ──────────────────────────────────────────────────────────────────

/** Look up a circuit by its string ID. Returns undefined if not found. */
export const getTrackById = (id: string): TrackInfo | undefined =>
  TRACK_REGISTRY.find((t) => t.id === id);

/** Returns only circuits with real FastF1 telemetry-derived SVG paths. */
export const getLiveDataTracks = (): TrackInfo[] =>
  TRACK_REGISTRY.filter((t) => t.hasLiveData);

/** Returns circuits that lack live telemetry data (future/speculative). */
export const getSpeculativeTracks = (): TrackInfo[] =>
  TRACK_REGISTRY.filter((t) => !t.hasLiveData);

// ─── TrackDisplay ─────────────────────────────────────────────────────────────

interface TrackDisplayProps extends TrackProps {
  trackId: string;
}

/**
 * Resolves a track ID to the correct SVG component and renders it with the
 * provided props. Returns null when the ID is not found in TRACK_REGISTRY.
 */
export const TrackDisplay: React.FC<TrackDisplayProps> = ({ trackId, ...props }) => {
  const track = getTrackById(trackId);
  if (!track) return null;
  const TrackComponent = track.component;
  return <TrackComponent {...props} />;
};

export default TrackDisplay;

